{
  "domain_analysis": {
    "business_context": "Parcel delivery logistics platform managing shipment lifecycle from creation through transit to delivery, with weight-based pricing tiers.",
    "bounded_context": "Shipment Management — covers shipment creation, state transitions, weight validation, and pricing classification.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "A domain entity representing a parcel moving from a pickup address to a delivery address, with a defined weight and lifecycle state." },
      { "term": "Pickup Address", "definition": "The origin location where the parcel is collected from the sender." },
      { "term": "Delivery Address", "definition": "The destination location where the parcel is delivered to the recipient." },
      { "term": "Shipment State", "definition": "The lifecycle phase of a shipment. Valid states: Pending, In Transit, Delivered." },
      { "term": "Weight Bracket", "definition": "A pricing classification tier determined by the shipment's weight: Standard (0–10 kg), Heavy (10–50 kg), Freight (>50 kg)." },
      { "term": "Standard", "definition": "Weight bracket for shipments weighing more than 0 kg up to and including 10 kg." },
      { "term": "Heavy", "definition": "Weight bracket for shipments weighing more than 10 kg up to and including 50 kg." },
      { "term": "Freight", "definition": "Weight bracket for shipments weighing more than 50 kg up to and including 1000 kg." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A shipment requires both a pickup address and a delivery address at creation time.",
      "invariant": true,
      "invariant_justification": "A shipment without both endpoints is physically meaningless — there is no origin or destination. This is a data integrity constraint; violating it produces a corrupt entity.",
      "testable_assertion": "Any attempt to create a shipment with a missing or empty pickup address or delivery address must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Shipment state transitions are unidirectional: Pending → In Transit → Delivered. No backward transitions are permitted.",
      "invariant": true,
      "invariant_justification": "State regression (e.g., In Transit back to Pending) violates the physical reality of the delivery process and would corrupt audit trails and downstream integrations. This is a state integrity constraint.",
      "testable_assertion": "A shipment in state 'In Transit' cannot transition to 'Pending'. A shipment in state 'Delivered' cannot transition to any other state."
    },
    {
      "id": "BR-3",
      "rule": "Delivered is a terminal state — no further state changes are allowed.",
      "invariant": true,
      "invariant_justification": "Delivery is a physical, real-world finality. Reversing it would break billing, SLA tracking, proof-of-delivery records, and customer notifications. This is a hard consistency constraint.",
      "testable_assertion": "Any attempt to change the state of a Delivered shipment must be rejected regardless of the target state."
    },
    {
      "id": "BR-4",
      "rule": "Shipment weight must be strictly greater than 0 kg and must not exceed 1000 kg.",
      "invariant": true,
      "invariant_justification": "Zero or negative weight is physically impossible for a real parcel. The 1000 kg upper bound represents a physical/operational hard limit (vehicle capacity, safety regulations). Violating either corrupts pricing and operational planning.",
      "testable_assertion": "A shipment with weight <= 0 or weight > 1000 must be rejected at creation and at any subsequent weight update."
    },
    {
      "id": "BR-5",
      "rule": "Weight bracket classification: Standard = weight in (0, 10] kg; Heavy = weight in (10, 50] kg; Freight = weight in (50, 1000] kg.",
      "invariant": false,
      "invariant_justification": "The bracket thresholds and names are business policy — a VP could adjust the boundaries (e.g., move Heavy to 15 kg) or add new tiers without corrupting system state.",
      "testable_assertion": "A 10 kg shipment is classified as Standard. A 10.01 kg shipment is classified as Heavy. A 50 kg shipment is classified as Heavy. A 50.01 kg shipment is classified as Freight."
    },
    {
      "id": "BR-6",
      "rule": "New shipments are created in the Pending state.",
      "invariant": true,
      "invariant_justification": "Creating a shipment directly in 'In Transit' or 'Delivered' would bypass pickup scheduling, validation, and audit. Initial state integrity is a system consistency constraint.",
      "testable_assertion": "A newly created shipment must have state equal to 'Pending'."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A valid pickup address, delivery address, and weight of 5 kg",
      "when": "A shipment is created",
      "then": "The shipment is persisted in state 'Pending' with weight bracket 'Standard'"
    },
    {
      "id": "AC-2",
      "given": "A request to create a shipment with a missing delivery address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating the delivery address is required"
    },
    {
      "id": "AC-3",
      "given": "A request to create a shipment with a missing pickup address",
      "when": "The creation is attempted",
      "then": "The system rejects the request with a validation error indicating the pickup address is required"
    },
    {
      "id": "AC-4",
      "given": "A shipment in state 'Pending'",
      "when": "The shipment is transitioned to 'In Transit'",
      "then": "The state changes to 'In Transit' successfully"
    },
    {
      "id": "AC-5",
      "given": "A shipment in state 'In Transit'",
      "when": "An attempt is made to transition it back to 'Pending'",
      "then": "The system rejects the transition with an error indicating backward state changes are not permitted"
    },
    {
      "id": "AC-6",
      "given": "A shipment in state 'In Transit'",
      "when": "The shipment is transitioned to 'Delivered'",
      "then": "The state changes to 'Delivered' successfully"
    },
    {
      "id": "AC-7",
      "given": "A shipment in state 'Delivered'",
      "when": "Any state transition is attempted (to Pending or In Transit)",
      "then": "The system rejects the transition with an error indicating delivered shipments are final"
    },
    {
      "id": "AC-8",
      "given": "A shipment creation request with weight of 0 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with an error indicating weight must be positive"
    },
    {
      "id": "AC-9",
      "given": "A shipment creation request with weight of 1001 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with an error indicating weight cannot exceed 1000 kg"
    },
    {
      "id": "AC-10",
      "given": "A shipment creation request with weight of -5 kg",
      "when": "The creation is attempted",
      "then": "The system rejects the request with an error indicating weight must be positive"
    },
    {
      "id": "AC-11",
      "given": "A shipment with weight of exactly 10 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as 'Standard'"
    },
    {
      "id": "AC-12",
      "given": "A shipment with weight of 10.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as 'Heavy'"
    },
    {
      "id": "AC-13",
      "given": "A shipment with weight of exactly 50 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as 'Heavy'"
    },
    {
      "id": "AC-14",
      "given": "A shipment with weight of 50.01 kg",
      "when": "The weight bracket is determined",
      "then": "The shipment is classified as 'Freight'"
    },
    {
      "id": "AC-15",
      "given": "A shipment in state 'Pending'",
      "when": "An attempt is made to transition directly to 'Delivered'",
      "then": "The system rejects the transition with an error indicating shipments must pass through 'In Transit' before delivery"
    }
  ],

  "edge_cases": [
    { "scenario": "Weight at exact boundary of 10 kg", "expected_behavior": "Classified as Standard (upper-inclusive boundary). This is a common source of off-by-one bugs." },
    { "scenario": "Weight at exact boundary of 50 kg", "expected_behavior": "Classified as Heavy (upper-inclusive boundary)." },
    { "scenario": "Weight at exact boundary of 1000 kg", "expected_behavior": "Accepted — 1000 kg is the maximum allowed weight, classified as Freight." },
    { "scenario": "Weight of 0.001 kg (fractional near-zero)", "expected_behavior": "Accepted — weight is positive. Classified as Standard. However, operationally suspicious; may warrant a business warning." },
    { "scenario": "Pending → Delivered direct skip", "expected_behavior": "Rejected. The spec implies a strict linear progression: Pending → In Transit → Delivered. Skipping In Transit would mean the parcel was never picked up." },
    { "scenario": "Duplicate transition (In Transit → In Transit)", "expected_behavior": "Spec is silent. Recommend idempotent acceptance (no-op) rather than error, but this needs product clarification." },
    { "scenario": "Pickup address and delivery address are identical", "expected_behavior": "Spec does not prohibit this. Technically valid but operationally suspicious. Recommend a soft warning, not a hard rejection." },
    { "scenario": "Weight provided as zero", "expected_behavior": "Rejected. Weight must be strictly positive (greater than 0)." }
  ],

  "business_impact": {
    "financial": "Correct weight bracket classification directly determines pricing. Misclassification at boundaries (especially 10 kg and 50 kg) leads to revenue leakage or customer overcharges. Enforcing the 1000 kg cap prevents accepting shipments that exceed operational capacity.",
    "operational": "Strict state machine enforcement prevents invalid shipment states that would corrupt dispatch, tracking, and proof-of-delivery workflows. Downstream systems (billing, notifications, SLA monitoring) depend on state integrity.",
    "user": "Customers expect clear feedback on why a shipment was rejected. Transparent weight bracket classification builds trust in pricing. Immutable delivery status provides reliable tracking information.",
    "risk": "Primary risk is boundary misclassification (off-by-one at 10 kg and 50 kg thresholds). Secondary risk is state machine bypass allowing invalid transitions, which would corrupt audit trails and potentially violate contractual SLAs. No regulatory or compliance dimensions are mentioned in the spec.",
    "stakeholders_affected": [
      { "group": "Shippers (senders)", "impact": "Must provide valid addresses and weight. Pricing transparency depends on correct bracket assignment." },
      { "group": "Recipients", "impact": "Delivery finality ensures reliable tracking. State integrity prevents false delivery notifications." },
      { "group": "Operations / Dispatch", "impact": "State machine integrity ensures dispatchers work with accurate shipment statuses. No phantom re-pending of in-transit parcels." },
      { "group": "Finance / Billing", "impact": "Weight bracket classification is the basis for invoicing. Errors cascade directly into revenue." },
      { "group": "Customer Support", "impact": "Clear rejection messages reduce support tickets. Immutable delivered state prevents disputes about shipment status." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is concise and internally consistent with no contradictions. Core state machine and weight rules are clear. Confidence is not higher because: (1) boundary inclusivity for weight brackets is ambiguous — '0-10 kg' and '10-50 kg' overlap at exactly 10 kg, requiring an interpretation choice; (2) whether Pending → Delivered skip is allowed is implied but not explicitly stated; (3) the spec is silent on idempotent transitions, weight mutability after creation, and address format validation; (4) no mention of cancellation as a state, which is unusual for a real logistics platform.",
    "high_confidence_areas": [
      "State machine directionality: Pending → In Transit → Delivered with no backward transitions",
      "Delivered is terminal and immutable",
      "Weight must be positive and <= 1000 kg",
      "Both pickup and delivery addresses are required for creation",
      "Three weight brackets exist with the described ranges"
    ],
    "low_confidence_areas": [
      "Boundary inclusivity at 10 kg and 50 kg — spec says '0-10' and '10-50' which overlaps; interpreted as upper-inclusive per bracket",
      "Whether Pending → Delivered direct skip is allowed (inferred as disallowed from the sequential nature of the process)",
      "Idempotent same-state transitions (e.g., In Transit → In Transit) — spec is silent",
      "Whether weight can be modified after shipment creation",
      "Absence of a Cancelled state — unusual for production logistics"
    ],
    "assumptions": [
      "Weight brackets are upper-inclusive: Standard = (0, 10], Heavy = (10, 50], Freight = (50, 1000]",
      "Pending → Delivered direct transition is not permitted; shipments must pass through In Transit",
      "Shipments are always created in Pending state",
      "Weight is set at creation time and the spec does not describe mutability",
      "Address validation rules (format, geocoding) are out of scope for this spec"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Weight bracket boundaries overlap at exactly 10 kg and 50 kg. The spec says '0-10 kg is standard, 10-50 kg is heavy' — a 10 kg parcel matches both descriptions. We have assumed upper-inclusive (10 kg = Standard, 50 kg = Heavy) but this needs explicit product confirmation.",
      "affected_stakeholders": ["Finance / Billing", "Shippers (senders)"],
      "options": ["10 kg is Standard (upper-inclusive per lower bracket)", "10 kg is Heavy (lower-inclusive per upper bracket)"],
      "recommendation": "10 kg = Standard, 50 kg = Heavy (upper-inclusive per lower bracket). This is the more customer-friendly interpretation and follows common industry practice."
    },
    {
      "type": "ambiguity",
      "description": "The spec does not explicitly address whether a shipment can skip from Pending directly to Delivered. The linear description implies sequential progression but does not state it as a rule.",
      "affected_stakeholders": ["Operations / Dispatch", "Recipients"],
      "options": ["Allow Pending → Delivered (for edge cases like in-store pickup)", "Forbid Pending → Delivered (enforce full lifecycle)"],
      "recommendation": "Forbid Pending → Delivered. In logistics, a parcel must be picked up (In Transit) before it can be delivered. Skipping this breaks operational traceability."
    },
    {
      "type": "missing_context",
      "description": "No Cancelled state is defined. Real logistics platforms almost always support cancellation from Pending (and sometimes from In Transit). This omission likely means it is out of scope for this iteration, but it should be confirmed.",
      "affected_stakeholders": ["Shippers (senders)", "Customer Support", "Finance / Billing"],
      "options": ["Confirm cancellation is intentionally out of scope", "Add Cancelled as a valid state from Pending"],
      "recommendation": "Confirm with product manager that cancellation is intentionally deferred. Flag it as a known gap for the next iteration."
    }
  ],

  "rejection_reasons": []
}

